import React, { useEffect, useState } from 'react'

interface BillboardStatsProps {
	getBillboardStats: () => {
		placements: Record<string, number>
		impressions: Record<string, number>
		maxPossibleImpressions: Record<string, number>
		trackLength: number
		totalSegments: number
		totalLaps: number
	} | null
	isVisible?: boolean
}

export const BillboardStats: React.FC<BillboardStatsProps> = ({
	getBillboardStats,
	isVisible = false,
}) => {
	const [stats, setStats] = useState<ReturnType<typeof getBillboardStats>>(null)

	useEffect(() => {
		if (isVisible) {
			const interval = setInterval(() => {
				const newStats = getBillboardStats()
				if (newStats) {
					setStats(newStats)
				}
			}, 1000) // Update every second

			return () => clearInterval(interval)
		}
	}, [getBillboardStats, isVisible])

	if (!isVisible || !stats) return null

	const billboards = Object.keys(stats.placements).sort()

	return (
		<div className="billboard-stats" style={{ width: '100%', height: '9rem', overflowY: 'scroll' }}>
			<h4 className="billboard-title">Billboard Analytics</h4>
			<div style={{ fontSize: '0.75rem', marginBottom: '0.5rem', color: '#d1d5db' }}>
				<div>
					Track: {stats.trackLength}m | Laps: {stats.totalLaps}
				</div>
			</div>
			<table style={{ width: '100%', fontSize: '0.75rem' }}>
				<thead>
					<tr style={{ borderBottom: '1px solid #4b5563', fontSize: '0.625rem' }}>
						<th style={{ textAlign: 'left', paddingBottom: '0.125rem' }}>Billboard</th>
						<th style={{ textAlign: 'center', paddingBottom: '0.125rem' }}>Placed</th>
						<th style={{ textAlign: 'center', paddingBottom: '0.125rem' }}>Shown</th>
						<th style={{ textAlign: 'right', paddingBottom: '0.125rem' }}>%</th>
					</tr>
				</thead>
				<tbody>
					{billboards.map(billboard => {
						const placed = stats.placements[billboard] || 0
						const shown = stats.impressions[billboard] || 0
						const maxPossible = stats.maxPossibleImpressions[billboard] || 0
						const percentage =
							maxPossible > 0 ? ((shown / maxPossible) * 100).toFixed(0) : '0'

						return (
							<tr key={billboard} style={{ borderBottom: '1px solid #374151' }}>
								<td style={{ padding: '0.125rem 0', fontSize: '0.625rem' }}>
									{billboard.replace('BILLBOARD', 'B')}
								</td>
								<td style={{ textAlign: 'center', padding: '0.125rem 0' }}>{placed}</td>
								<td style={{ textAlign: 'center', padding: '0.125rem 0' }}>{shown}</td>
								<td style={{ textAlign: 'right', padding: '0.125rem 0' }}>{percentage}%</td>
							</tr>
						)
					})}
				</tbody>
				<tfoot>
					<tr style={{ fontWeight: 'bold', borderTop: '1px solid #6b7280' }}>
						<td style={{ paddingTop: '0.25rem', fontSize: '0.75rem' }}>TOTAL</td>
						<td style={{ textAlign: 'center', paddingTop: '0.25rem' }}>
							{Object.values(stats.placements).reduce((a, b) => a + b, 0)}
						</td>
						<td style={{ textAlign: 'center', paddingTop: '0.25rem' }}>
							{Object.values(stats.impressions).reduce((a, b) => a + b, 0)}
						</td>
						<td style={{ textAlign: 'right', paddingTop: '0.25rem' }}>
							{Object.values(stats.maxPossibleImpressions).reduce(
								(a, b) => a + b,
								0
							) > 0
								? (
										(Object.values(stats.impressions).reduce(
											(a, b) => a + b,
											0
										) /
											Object.values(stats.maxPossibleImpressions).reduce(
												(a, b) => a + b,
												0
											)) *
										100
									).toFixed(0)
								: '0'}
							%
						</td>
					</tr>
				</tfoot>
			</table>
			<div style={{ marginTop: '0.25rem', fontSize: '0.625rem', color: '#9ca3af' }}>
				<p>% = Shown vs Max Possible ({stats.totalLaps} laps)</p>
			</div>
		</div>
	)
}
