import type {
	Sprite,
	BackgroundLayer,
	RoadSegment,
	CoinAnimation,
	CrashAnimation,
} from '../types'
import { COLORS, SPRITES } from '../constants'
import { MathUtils } from '../utils/math'

/**
 * Optimized rendering engine for 3D car racing game
 */
export class RenderEngine {
	private ctx: CanvasRenderingContext2D
	private width: number
	private height: number
	public resolution: number
	private cameraDepth: number = 0.84 // Default camera depth

	constructor(ctx: CanvasRenderingContext2D, width: number, height: number) {
		this.ctx = ctx
		this.width = width
		this.height = height
		this.resolution = height / 480
	}

	/**
	 * Set camera depth for visibility calculations
	 */
	setCameraDepth(depth: number): void {
		this.cameraDepth = depth
	}

	/**
	 * Update canvas dimensions
	 */
	updateDimensions(width: number, height: number): void {
		this.width = width
		this.height = height
		this.resolution = height / 480
	}

	/**
	 * Clear the canvas
	 */
	clear(): void {
		this.ctx.clearRect(0, 0, this.width, this.height)
	}

	/**
	 * Draw a polygon
	 * Optimized to reduce canvas state changes
	 */
	private polygon(
		x1: number,
		y1: number,
		x2: number,
		y2: number,
		x3: number,
		y3: number,
		x4: number,
		y4: number,
		color: string
	): void {
		this.ctx.fillStyle = color
		this.ctx.beginPath()
		this.ctx.moveTo(x1, y1)
		this.ctx.lineTo(x2, y2)
		this.ctx.lineTo(x3, y3)
		this.ctx.lineTo(x4, y4)
		this.ctx.closePath()
		this.ctx.fill()
	}

	/**
	 * Draw a road segment
	 */
	segment(
		lanes: number,
		x1: number,
		y1: number,
		w1: number,
		x2: number,
		y2: number,
		w2: number,
		fog: number,
		color: any
	): void {
		const r1 = this.rumbleWidth(w1, lanes)
		const r2 = this.rumbleWidth(w2, lanes)
		const l1 = this.laneMarkerWidth(w1, lanes)
		const l2 = this.laneMarkerWidth(w2, lanes)

		// Grass
		this.ctx.fillStyle = color.grass
		this.ctx.fillRect(0, y2, this.width, y1 - y2)

		// Rumble strips
		this.polygon(
			x1 - w1 - r1,
			y1,
			x1 - w1,
			y1,
			x2 - w2,
			y2,
			x2 - w2 - r2,
			y2,
			color.rumble
		)
		this.polygon(
			x1 + w1 + r1,
			y1,
			x1 + w1,
			y1,
			x2 + w2,
			y2,
			x2 + w2 + r2,
			y2,
			color.rumble
		)

		// Road
		this.polygon(x1 - w1, y1, x1 + w1, y1, x2 + w2, y2, x2 - w2, y2, color.road)

		// Lane markers
		if (color.lane) {
			const lanew1 = (w1 * 2) / lanes
			const lanew2 = (w2 * 2) / lanes
			let lanex1 = x1 - w1 + lanew1
			let lanex2 = x2 - w2 + lanew2

			for (let lane = 1; lane < lanes; lane++) {
				this.polygon(
					lanex1 - l1 / 2,
					y1,
					lanex1 + l1 / 2,
					y1,
					lanex2 + l2 / 2,
					y2,
					lanex2 - l2 / 2,
					y2,
					color.lane
				)
				lanex1 += lanew1
				lanex2 += lanew2
			}
		}

		// Fog
		this.fog(0, y1, this.width, y2 - y1, fog)
	}

	/**
	 * Draw background layer
	 * Optimized for seamless scrolling
	 */
	background(
		background: HTMLImageElement,
		layer: BackgroundLayer,
		rotation: number,
		offset: number
	): void {
		rotation = rotation || 0
		offset = offset || 0

		const imageW = layer.w / 2
		const imageH = layer.h

		const sourceX = layer.x + (Math.floor(layer.w * rotation) % layer.w)
		const sourceY = layer.y
		const sourceW = Math.min(imageW, layer.w - (sourceX - layer.x))
		const sourceH = imageH

		const destX = 0
		const destY = Math.floor(offset)
		const destW = Math.floor(this.width * (sourceW / imageW))
		const destH = this.height

		// Draw main portion
		this.ctx.drawImage(
			background,
			sourceX,
			sourceY,
			sourceW,
			sourceH,
			destX,
			destY,
			destW,
			destH
		)

		// Draw wrapped portion for seamless scrolling
		if (sourceW < imageW) {
			this.ctx.drawImage(
				background,
				layer.x,
				sourceY,
				imageW - sourceW,
				sourceH,
				destW - 1,
				destY,
				this.width - destW,
				destH
			)
		}
	}

	/**
	 * Draw a sprite
	 * Optimized with clipping support
	 */
	sprite(
		roadWidth: number,
		sprites: HTMLImageElement,
		sprite: Sprite,
		scale: number,
		destX: number,
		destY: number,
		offsetX: number = 0,
		offsetY: number = 0,
		clipY?: number
	): void {
		const destW =
			((sprite.w * scale * this.width) / 2) * (SPRITES.SCALE * roadWidth)
		const destH =
			((sprite.h * scale * this.width) / 2) * (SPRITES.SCALE * roadWidth)

		destX = destX + destW * offsetX
		destY = destY + destH * offsetY

		const clipH = clipY ? Math.max(0, destY + destH - clipY) : 0

		if (clipH < destH) {
			this.ctx.drawImage(
				sprites,
				sprite.x,
				sprite.y,
				sprite.w,
				sprite.h - (sprite.h * clipH) / destH,
				destX,
				destY,
				destW,
				destH - clipH
			)
		}
	}

	/**
	 * Draw the player car
	 * Includes bounce effect based on speed
	 */
	player(
		roadWidth: number,
		sprites: HTMLImageElement,
		speedPercent: number,
		scale: number,
		destX: number,
		destY: number,
		steer: number,
		updown: number
	): void {
		const bounce =
			1.5 *
			Math.random() *
			speedPercent *
			this.resolution *
			MathUtils.randomChoice([-1, 1])

		let sprite: Sprite
		if (steer < 0) {
			sprite = updown > 0 ? SPRITES.PLAYER_UPHILL_LEFT : SPRITES.PLAYER_LEFT
		} else if (steer > 0) {
			sprite = updown > 0 ? SPRITES.PLAYER_UPHILL_RIGHT : SPRITES.PLAYER_RIGHT
		} else {
			sprite =
				updown > 0 ? SPRITES.PLAYER_UPHILL_STRAIGHT : SPRITES.PLAYER_STRAIGHT
		}

		this.sprite(
			roadWidth,
			sprites,
			sprite,
			scale,
			destX,
			destY + bounce,
			-0.5,
			-1
		)
	}

	/**
	 * Draw fog effect
	 * Optimized to skip when fog is minimal
	 */
	private fog(
		x: number,
		y: number,
		width: number,
		height: number,
		fog: number
	): void {
		if (fog < 1 && fog > 0.01) {
			this.ctx.globalAlpha = 1 - fog
			this.ctx.fillStyle = COLORS.FOG
			this.ctx.fillRect(x, y, width, height)
			this.ctx.globalAlpha = 1
		}
	}

	/**
	 * Calculate rumble width
	 */
	private rumbleWidth(projectedRoadWidth: number, lanes: number): number {
		return projectedRoadWidth / Math.max(6, 2 * lanes)
	}

	/**
	 * Calculate lane marker width
	 */
	private laneMarkerWidth(projectedRoadWidth: number, lanes: number): number {
		return projectedRoadWidth / Math.max(32, 8 * lanes)
	}

	/**
	 * Batch render cars for performance
	 */
	renderCars(
		segments: RoadSegment[],
		baseSegmentIndex: number,
		drawDistance: number,
		roadWidth: number,
		sprites: HTMLImageElement
	): void {
		// Render from back to front
		for (let n = drawDistance - 1; n > 0; n--) {
			const segment = segments[(baseSegmentIndex + n) % segments.length]

			for (const car of segment.cars) {
				const spriteScale = MathUtils.interpolate(
					segment.p1.screen.scale,
					segment.p2.screen.scale,
					car.percent || 0
				)
				const spriteX =
					MathUtils.interpolate(
						segment.p1.screen.x,
						segment.p2.screen.x,
						car.percent || 0
					) +
					(spriteScale * car.offset * roadWidth * this.width) / 2
				const spriteY = MathUtils.interpolate(
					segment.p1.screen.y,
					segment.p2.screen.y,
					car.percent || 0
				)

				this.sprite(
					roadWidth,
					sprites,
					car.sprite,
					spriteScale,
					spriteX,
					spriteY,
					-0.5,
					-1,
					segment.clip
				)
			}
		}
	}

	/**
	 * Batch render sprites for performance
	 */
	renderSprites(
		segments: RoadSegment[],
		baseSegmentIndex: number,
		drawDistance: number,
		roadWidth: number,
		sprites: HTMLImageElement
	): void {
		// Render from back to front
		for (let n = drawDistance - 1; n > 0; n--) {
			const segment = segments[(baseSegmentIndex + n) % segments.length]

			for (const sprite of segment.sprites) {
				const spriteScale = segment.p1.screen.scale
				const spriteX =
					segment.p1.screen.x +
					(spriteScale * sprite.offset * roadWidth * this.width) / 2
				const spriteY = segment.p1.screen.y

				this.sprite(
					roadWidth,
					sprites,
					sprite.source,
					spriteScale,
					spriteX,
					spriteY,
					sprite.offset < 0 ? -1 : 0,
					-1,
					segment.clip
				)
			}
		}
	}

	/**
	 * Render all objects (sprites and cars) in correct z-order
	 */
	renderObjects(
		segments: RoadSegment[],
		baseSegmentIndex: number,
		drawDistance: number,
		roadWidth: number,
		sprites: HTMLImageElement,
		onBillboardRender?: (
			sprite: Sprite,
			segmentIndex: number,
			offset: number
		) => void
	): void {
		// Render from back to front
		for (let n = drawDistance - 1; n > 0; n--) {
			const segment = segments[(baseSegmentIndex + n) % segments.length]

			// Render sprites first (they are at the segment start position)
			for (const sprite of segment.sprites) {
				const spriteScale = segment.p1.screen.scale
				const spriteX =
					segment.p1.screen.x +
					(spriteScale * sprite.offset * roadWidth * this.width) / 2
				const spriteY = segment.p1.screen.y

				// Check if sprite is visible (not clipped and within screen bounds)
				if (
					segment.clip &&
					segment.p1.camera.z > this.cameraDepth &&
					spriteY < segment.clip
				) {
					// Notify about billboard render if callback provided
					if (onBillboardRender) {
						onBillboardRender(sprite.source, segment.index, sprite.offset)
					}
				}

				this.sprite(
					roadWidth,
					sprites,
					sprite.source,
					spriteScale,
					spriteX,
					spriteY,
					sprite.offset < 0 ? -1 : 0,
					-1,
					segment.clip
				)
			}

			// Then render cars (they can be anywhere within the segment)
			for (const car of segment.cars) {
				const spriteScale = MathUtils.interpolate(
					segment.p1.screen.scale,
					segment.p2.screen.scale,
					car.percent || 0
				)
				const spriteX =
					MathUtils.interpolate(
						segment.p1.screen.x,
						segment.p2.screen.x,
						car.percent || 0
					) +
					(spriteScale * car.offset * roadWidth * this.width) / 2
				const spriteY = MathUtils.interpolate(
					segment.p1.screen.y,
					segment.p2.screen.y,
					car.percent || 0
				)

				this.sprite(
					roadWidth,
					sprites,
					car.sprite,
					spriteScale,
					spriteX,
					spriteY,
					-0.5,
					-1,
					segment.clip
				)
			}
		}
	}

	/**
	 * Render coin collection animations
	 */
	renderCoinAnimations(animations: CoinAnimation[], currentTime: number): void {
		const ctx = this.ctx
		ctx.save()

		for (const anim of animations) {
			const elapsed = currentTime - anim.startTime
			const progress = Math.min(elapsed / 500, 1) // 0.5 second animation

			if (progress >= 1) continue

			// Fade out effect
			const alpha = 1 - progress

			// Particle burst effect
			const particleCount = 6
			const particleRadius = 3
			const burstRadius = 50 * progress

			ctx.globalAlpha = alpha * 0.8
			ctx.fillStyle = '#FFD700' // Gold color

			for (let i = 0; i < particleCount; i++) {
				const angle = (i / particleCount) * Math.PI * 2
				const x = anim.x + Math.cos(angle) * burstRadius
				const y = anim.y + Math.sin(angle) * burstRadius

				ctx.beginPath()
				ctx.arc(x, y, particleRadius, 0, Math.PI * 2)
				ctx.fill()
			}

			// "+X puntos" text
			ctx.globalAlpha = alpha
			ctx.font = 'bold 24px Arial'
			ctx.fillStyle = '#FFD700'
			ctx.strokeStyle = '#000000'
			ctx.lineWidth = 3

			const text = `+${anim.points} puntos`
			const textY = anim.y - 30 * progress // Float upward

			ctx.strokeText(text, anim.x - 40, textY)
			ctx.fillText(text, anim.x - 40, textY)
		}

		ctx.restore()
	}

	/**
	 * Render crash/collision animations
	 */
	renderCrashAnimations(
		animations: CrashAnimation[],
		currentTime: number
	): void {
		const ctx = this.ctx
		ctx.save()

		for (const anim of animations) {
			const elapsed = currentTime - anim.startTime
			const progress = Math.min(elapsed / 500, 1) // 0.5 second animation

			if (progress >= 1) continue

			// Shake effect
			const shakeX = (Math.random() - 0.5) * 10 * (1 - progress)
			const shakeY = (Math.random() - 0.5) * 10 * (1 - progress)

			// Fade out effect
			const alpha = 1 - progress

			// Red explosion particles
			const particleCount = 8
			const particleRadius = 4
			const burstRadius = 60 * progress

			ctx.globalAlpha = alpha * 0.9

			for (let i = 0; i < particleCount; i++) {
				const angle = (i / particleCount) * Math.PI * 2
				const x = anim.x + Math.cos(angle) * burstRadius + shakeX
				const y = anim.y + Math.sin(angle) * burstRadius + shakeY

				// Red to orange gradient
				const color = i % 2 === 0 ? '#FF0000' : '#FF6600'
				ctx.fillStyle = color

				ctx.beginPath()
				ctx.arc(x, y, particleRadius * (1 - progress * 0.5), 0, Math.PI * 2)
				ctx.fill()
			}

			// "-3 puntos" text with shake
			ctx.globalAlpha = alpha
			ctx.font = 'bold 28px Arial'
			ctx.fillStyle = '#FF0000'
			ctx.strokeStyle = '#000000'
			ctx.lineWidth = 4

			const text = '-3 puntos'
			const textX = anim.x - 50 + shakeX
			const textY = anim.y - 20 * progress + shakeY // Float upward

			ctx.strokeText(text, textX, textY)
			ctx.fillText(text, textX, textY)

			// Impact flash effect
			if (progress < 0.1) {
				ctx.globalAlpha = (1 - progress * 10) * 0.5
				ctx.fillStyle = '#FFFFFF'
				ctx.beginPath()
				ctx.arc(anim.x, anim.y, 50, 0, Math.PI * 2)
				ctx.fill()
			}
		}

		ctx.restore()
	}
}
