import type { Car, RoadSegment, InputState } from '../types'
import { SPRITES } from '../constants'
import { MathUtils } from '../utils/math'

/**
 * Physics and collision engine for 3D car racing game
 * Optimized for performance with spatial optimizations
 */
export class PhysicsEngine {
	private maxSpeed: number
	private accel: number
	private breaking: number
	private decel: number
	private offRoadDecel: number
	private offRoadLimit: number
	private centrifugal: number
	private trackLength: number

	constructor(config: {
		maxSpeed: number
		accel: number
		breaking: number
		decel: number
		offRoadDecel: number
		offRoadLimit: number
		centrifugal: number
		trackLength: number
	}) {
		this.maxSpeed = config.maxSpeed
		this.accel = config.accel
		this.breaking = config.breaking
		this.decel = config.decel
		this.offRoadDecel = config.offRoadDecel
		this.offRoadLimit = config.offRoadLimit
		this.centrifugal = config.centrifugal
		this.trackLength = config.trackLength
	}

	/**
	 * Update track length
	 */
	updateTrackLength(trackLength: number): void {
		this.trackLength = trackLength
	}

	/**
	 * Update player physics
	 */
	updatePlayer(
		playerX: number,
		speed: number,
		position: number,
		inputState: InputState,
		playerSegment: RoadSegment,
		dt: number,
		_findSegment: (z: number) => RoadSegment,
		//roadWidth: number = 2000,
		canvasWidth: number = 720,
		canvasHeight: number = 960
	): {
		playerX: number
		speed: number
		position: number
		pointsEarned: number
		crashed: boolean
		coinCollected?: { x: number; y: number }
		crashPosition?: { x: number; y: number }
	} {
		const playerW = SPRITES.PLAYER_STRAIGHT.w * SPRITES.SCALE
		const speedPercent = speed / this.maxSpeed
		const dx = dt * 2 * speedPercent
		let pointsEarned = 0
		let crashed = false

		// Handle movement
		if (inputState.left) {
			playerX = playerX - dx
		} else if (inputState.right) {
			playerX = playerX + dx
		}

		// Apply centrifugal force
		playerX =
			playerX - dx * speedPercent * playerSegment.curve * this.centrifugal

		// Handle acceleration/deceleration
		if (inputState.faster) {
			speed = MathUtils.accelerate(speed, this.accel, dt)
		} else if (inputState.slower) {
			speed = MathUtils.accelerate(speed, this.breaking, dt)
		} else {
			speed = MathUtils.accelerate(speed, this.decel, dt)
		}

		// Handle off-road physics and sprite collisions
		if (playerX < -1 || playerX > 1) {
			if (speed > this.offRoadLimit) {
				speed = MathUtils.accelerate(speed, this.offRoadDecel, dt)
			}

			// Check sprite collisions
			for (const sprite of playerSegment.sprites) {
				const spriteW = sprite.source.w * SPRITES.SCALE
				if (
					MathUtils.overlap(
						playerX,
						playerW,
						sprite.offset + (spriteW / 2) * (sprite.offset > 0 ? 1 : -1),
						spriteW
					)
				) {
					speed = this.maxSpeed / 5
					position = MathUtils.increase(
						playerSegment.p1.world.z,
						-playerW,
						this.trackLength
					)
					break
				}
			}
		}

		// Handle coin collection
		let coinCollected: { x: number; y: number } | undefined
		for (let i = playerSegment.sprites.length - 1; i >= 0; i--) {
			const sprite = playerSegment.sprites[i]
			if (sprite.source === SPRITES.COIN) {
				const coinW = sprite.source.w * SPRITES.SCALE
				if (
					MathUtils.overlap(
						playerX,
						playerW,
						sprite.offset + (coinW / 10) * (sprite.offset > 0 ? 1 : -1),
						coinW
					)
				) {
					// Store coin position for animation
					// Since we're in the physics update, screen coordinates might not be available
					// We'll use a simple approximation based on player position
					coinCollected = {
						x: canvasWidth / 2 + sprite.offset * canvasWidth * 0.3, // Approximate screen position
						y: canvasHeight / 2 - 100, // Slightly above center
					}
					// Remove coin
					playerSegment.sprites.splice(i, 1)
					// Award points based on speed
					pointsEarned = Math.round(speed / 1000)
				}
			}
		}

		// Handle car collisions
		let crashPosition: { x: number; y: number } | undefined
		for (const car of playerSegment.cars) {
			const carW = car.sprite.w * SPRITES.SCALE
			if (speed > car.speed) {
				if (MathUtils.overlap(playerX, playerW, car.offset, carW, 0.6)) {
					speed = car.speed * (car.speed / speed)
					position = MathUtils.increase(car.z, -playerW, this.trackLength)
					pointsEarned = -3 // Crash penalty
					crashed = true
					// Store crash position for animation
					crashPosition = {
						x: canvasWidth / 2 + car.offset * canvasWidth * 0.3, // Approximate position of collision
						y: canvasHeight / 2 - 50, // Slightly above center
					}
					break
				}
			}
		}

		// Clamp values
		playerX = MathUtils.limit(playerX, -3, 3)
		speed = MathUtils.limit(speed, 0, this.maxSpeed)

		return {
			playerX,
			speed,
			position,
			pointsEarned,
			crashed,
			coinCollected,
			crashPosition,
		}
	}

	/**
	 * Update all cars with optimized AI
	 */
	updateCars(
		cars: Car[],
		dt: number,
		playerSegment: RoadSegment,
		playerX: number,
		playerSpeed: number,
		drawDistance: number,
		findSegment: (z: number) => RoadSegment,
		segments: RoadSegment[]
	): void {
		const playerW = SPRITES.PLAYER_STRAIGHT.w * SPRITES.SCALE

		for (const car of cars) {
			const oldSegment = findSegment(car.z)

			// Update car position
			car.z = MathUtils.increase(car.z, dt * car.speed, this.trackLength)
			car.percent = MathUtils.percentRemaining(car.z, 200) // segmentLength

			// Update car offset (AI steering)
			car.offset += this.updateCarOffset(
				car,
				oldSegment,
				playerSegment,
				playerW,
				playerX,
				playerSpeed,
				drawDistance,
				segments
			)

			// Move car to new segment if needed
			const newSegment = findSegment(car.z)
			if (oldSegment !== newSegment) {
				const index = oldSegment.cars.indexOf(car)
				if (index !== -1) {
					oldSegment.cars.splice(index, 1)
					newSegment.cars.push(car)
				}
			}
		}
	}

	/**
	 * Calculate car AI steering offset
	 */
	private updateCarOffset(
		car: Car,
		carSegment: RoadSegment,
		playerSegment: RoadSegment,
		playerW: number,
		playerX: number,
		playerSpeed: number,
		drawDistance: number,
		segments: RoadSegment[]
	): number {
		const lookahead = 20
		const carW = car.sprite.w * SPRITES.SCALE

		// Optimization: don't calculate AI for cars far from player
		if (carSegment.index - playerSegment.index > drawDistance) {
			return 0
		}

		// Look ahead for obstacles
		for (let i = 1; i < lookahead; i++) {
			const segment = segments[(carSegment.index + i) % segments.length]

			// Avoid player
			if (
				segment === playerSegment &&
				car.speed > playerSpeed &&
				MathUtils.overlap(playerX, playerW, car.offset, carW, 1.2)
			) {
				const dir = this.calculateAvoidanceDirection(playerX, car.offset)
				return (((dir * 1) / i) * (car.speed - playerSpeed)) / this.maxSpeed
			}

			// Avoid other cars
			for (const otherCar of segment.cars) {
				const otherCarW = otherCar.sprite.w * SPRITES.SCALE
				if (
					car.speed > otherCar.speed &&
					MathUtils.overlap(car.offset, carW, otherCar.offset, otherCarW, 1.2)
				) {
					const dir = this.calculateAvoidanceDirection(
						otherCar.offset,
						car.offset
					)
					return (
						(((dir * 1) / i) * (car.speed - otherCar.speed)) / this.maxSpeed
					)
				}
			}
		}

		// Return to road if off-road
		if (car.offset < -0.9) return 0.1
		else if (car.offset > 0.9) return -0.1
		else return 0
	}

	/**
	 * Calculate direction to avoid obstacle
	 */
	private calculateAvoidanceDirection(obstacleX: number, carX: number): number {
		if (obstacleX > 0.5) return -1
		else if (obstacleX < -0.5) return 1
		else return carX > obstacleX ? 1 : -1
	}

	/**
	 * Update background scroll offsets
	 */
	updateScrollOffsets(
		skyOffset: number,
		hillOffset: number,
		treeOffset: number,
		playerSegment: RoadSegment,
		startPosition: number,
		position: number,
		segmentLength: number,
		skySpeed: number,
		hillSpeed: number,
		treeSpeed: number
	): { skyOffset: number; hillOffset: number; treeOffset: number } {
		const deltaPosition = position - startPosition

		skyOffset = MathUtils.increase(
			skyOffset,
			(skySpeed * playerSegment.curve * deltaPosition) / segmentLength,
			1
		)
		hillOffset = MathUtils.increase(
			hillOffset,
			(hillSpeed * playerSegment.curve * deltaPosition) / segmentLength,
			1
		)
		treeOffset = MathUtils.increase(
			treeOffset,
			(treeSpeed * playerSegment.curve * deltaPosition) / segmentLength,
			1
		)

		return { skyOffset, hillOffset, treeOffset }
	}
}
