import React, { useState, useCallback, useRef, Suspense } from 'react'
import { GameHeader } from '../ui/GameHeader'
import { GameOverlay } from '../ui/GameOverlay'
import { isMobile } from '../../../../utils/functions'
import { PenaltyShootout3DProps, ShotResult } from './types'

const PenaltyShootout3DCore = React.lazy(() => import('./game'))

const PenaltyShootout3DGame: React.FC<PenaltyShootout3DProps> = ({
	lives = 5,
	setGameOver,
	setPointsEarned,
	brandColor = '#1a472a',
	gameTitle = 'PENALES 3D',
	brandLogo,
	maxPoints,
}) => {
	const containerRef = useRef<HTMLDivElement>(null)

	const [score, setScore] = useState(0)
	const [round, setRound] = useState(1)
	const [isGameStarted, setIsGameStarted] = useState(false)
	const [isGameOver, setIsGameOver] = useState(false)
	const [quitGame, setQuitGame] = useState(false)
	const [gameResult, setGameResult] = useState<{
		goals: number
		score: number
		won: boolean
	} | null>(null)

	const isMobileDevice = isMobile()

	const startGame = useCallback(() => {
		if (!isGameStarted) {
			setIsGameStarted(true)
			setIsGameOver(false)
			setScore(0)
			setRound(1)
			setQuitGame(false)
			setGameResult(null)
		}
	}, [isGameStarted])

	const cancelQuit = () => {
		setQuitGame(false)
	}

	const handleQuitConfirm = () => {
		setPointsEarned(score)
		setGameOver(true)
		setIsGameStarted(false)
		setIsGameOver(true)
	}

	const handleScoreUpdate = useCallback(
		(newScore: number) => {
			setScore(newScore)
			if (maxPoints && newScore >= maxPoints) {
				setIsGameOver(true)
				setGameResult({
					goals: 0,
					score: Math.min(newScore, maxPoints),
					won: true,
				})
			}
		},
		[maxPoints]
	)

	const handleRoundComplete = useCallback(
		(roundNum: number, _result: ShotResult) => {
			setRound(roundNum + 1)
		},
		[]
	)

	const handleGameOverFromEngine = useCallback(
		(finalGoals: number, totalScore: number) => {
			setIsGameOver(true)
			setGameResult({
				goals: finalGoals,
				score: totalScore,
				won: finalGoals >= Math.ceil(lives / 2),
			})
		},
		[lives]
	)

	const handleContinue = () => {
		setPointsEarned(score)
		setGameOver(true)
	}

	return (
		<div
			className="game-container game-column-narrow"
			style={{ backgroundColor: brandColor }}
			ref={containerRef}
		>
			{/* Game Header */}
			<GameHeader
				score={score}
				lives={lives - round + 1}
				brandColor={brandColor}
				isMobile={isMobileDevice}
				onQuit={() => setQuitGame(true)}
				showQuitButton={isGameStarted && !isGameOver}
				isQuitting={quitGame}
			/>

			{/* Game Canvas Area */}
			<div className="game-center-area">
				<div
					className="game-relative-area"
					style={{ aspectRatio: '400/600', maxHeight: '70vh' }}
				>
					{/* Start Screen */}
					{!isGameStarted && !isGameOver && (
						<GameOverlay
							type="custom"
							brandColor={brandColor}
							onAction={startGame}
							actionText="⚽ JUGAR 3D"
							showPressToStart={false}
							customContent={
								<div className="game-start-content">
									<h1 className="game-start-title game-animate-pulse" style={{ color: '#4ade80' }}>
										{gameTitle}
									</h1>
									{brandLogo && (
										<>
											<span className="game-brand-label">por:</span>
											<img
												src={brandLogo}
												alt="Brand Logo"
												className="game-brand-logo"
											/>
										</>
									)}
									<div className="game-start-instructions">
										<p>⚽ Tira {lives} penales en 3D</p>
										<p>👆 Desliza desde el balón hacia la portería</p>
										<p>🌀 Curva tu tiro para engañar al portero</p>
										<p>🏆 Anota {Math.ceil(lives / 2)}+ goles para ganar</p>
									</div>
									<div className="game-start-footer">
										<p>Tiros curvos = +25 pts | Esquinas = +50 pts</p>
									</div>
								</div>
							}
						/>
					)}

					{/* Active Game */}
					{isGameStarted && !isGameOver && (
						<Suspense fallback={<div className="game-loading-fallback"><div className="game-loading-text game-animate-pulse">Cargando 3D...</div></div>}>
						<PenaltyShootout3DCore
							onScoreUpdate={handleScoreUpdate}
							onRoundComplete={handleRoundComplete}
							onGameOver={handleGameOverFromEngine}
							totalRounds={lives}
						/>
						</Suspense>
					)}

					{/* Game Over Screen */}
					{isGameOver && gameResult && (
						<GameOverlay
							type="custom"
							brandColor={brandColor}
							onAction={handleContinue}
							actionText="Continuar"
							customContent={
								<div className="game-start-content-lg">
									<h1
										className="game-start-title-lg"
										style={{ color: gameResult.won ? '#4ade80' : '#f87171' }}
									>
										{gameResult.won ? '¡VICTORIA!' : 'DERROTA'}
									</h1>
									<div className="game-results-list">
										{Array.from({ length: lives }).map((_, i) => (
											<span
												key={i}
												style={{ fontSize: '1.5rem', opacity: i < gameResult.goals ? 1 : 0.3 }}
											>
												⚽
											</span>
										))}
									</div>
									<p style={{ fontSize: '1.25rem', color: 'white' }}>
										{gameResult.goals} de {lives} goles
									</p>
									<p style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#facc15' }}>
										{gameResult.score} puntos
									</p>
									{gameResult.goals === lives && (
										<p className="game-animate-pulse" style={{ fontSize: '1.125rem', color: '#fde047' }}>
											¡Puntuación perfecta! 🌟
										</p>
									)}
								</div>
							}
						/>
					)}

					{/* Quit Confirmation */}
					{quitGame && (
						<GameOverlay
							type="custom"
							title="¿Salir del Juego?"
							message={`¿Seguro? Registrarás tus puntos actuales (${score}) y terminarás la partida.`}
							brandColor={brandColor}
							customContent={
								<div className="game-quit-buttons">
									<button
										onClick={cancelQuit}
										className="game-quit-btn game-quit-btn-cancel"
									>
										Cancelar
									</button>
									<button
										onClick={handleQuitConfirm}
										className="game-quit-btn game-quit-btn-confirm"
									>
										Salir
									</button>
								</div>
							}
						/>
					)}
				</div>
			</div>
		</div>
	)
}

export default PenaltyShootout3DGame
