// Perspective compensation: shifts the ideal hit point slightly toward the
// player (negative Z) so that "perfect" timing aligns with where the note
// *visually* reaches the receptor ring under the perspective camera.
export const PERSPECTIVE_HIT_OFFSET = -0.4

